-- PG12-specific DDL features

CREATE TABLE gen_cols (
  id SERIAL PRIMARY KEY,
  first_name TEXT,
  last_name TEXT,
  email TEXT,
  full_name TEXT GENERATED ALWAYS AS (first_name || ' ' || last_name) STORED,
  email_upper TEXT GENERATED ALWAYS AS (upper(email)) STORED,
  json_data JSONB,
  name_from_json TEXT GENERATED ALWAYS AS (COALESCE(json_data->>'name', 'unknown')) STORED,
  year_created INT GENERATED ALWAYS AS (EXTRACT(YEAR FROM NOW())) STORED
);

CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY (id INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_BY_DEFAULT_AS_IDENTI (id INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_S (id INT GENERATED ALWAYS AS IDENTITY (START WITH 100) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_I (id INT GENERATED ALWAYS AS IDENTITY (INCREMENT BY 5) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_M (id INT GENERATED ALWAYS AS IDENTITY (MINVALUE 1 MAXVALUE 999999) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_N (id INT GENERATED ALWAYS AS IDENTITY (NO MINVALUE NO MAXVALUE) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_C (id INT GENERATED ALWAYS AS IDENTITY (CYCLE) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_N (id INT GENERATED ALWAYS AS IDENTITY (NO CYCLE) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_C (id INT GENERATED ALWAYS AS IDENTITY (CACHE 20) PRIMARY KEY, name TEXT);
CREATE TABLE id_GENERATED_ALWAYS_AS_IDENTITY_S (id INT GENERATED ALWAYS AS IDENTITY (START WITH 100 INCREMENT BY 5 MINVALUE 100 MAXVALUE 999999 CYCLE CACHE 20) PRIMARY KEY, name TEXT);
CREATE INDEX idx_include_single ON gen_cols (email) INCLUDE (full_name);
CREATE INDEX idx_include_multi ON gen_cols (id) INCLUDE (first_name, last_name, email);
CREATE UNIQUE INDEX idx_include_unique ON gen_cols (email) INCLUDE (full_name);
CREATE INDEX idx_include_partial ON gen_cols (id) INCLUDE (email) WHERE email IS NOT NULL;
CREATE INDEX idx_include_expr ON gen_cols ((upper(email))) INCLUDE (full_name);

CREATE COLLATION nd_collation (provider = icu, locale = 'en-u-ks-level2', deterministic = false);

CREATE TRIGGER trg_truncate AFTER TRUNCATE ON gen_cols FOR EACH STATEMENT EXECUTE FUNCTION fn_sql();

